35	class ParkingLotServiceTest {
36	
37	    // A mutable fake clock — tests move it forward to bill without sleeping.
38	    private final Instant[] now = { Instant.parse("2026-06-21T08:00:00Z") };
39	    private final Supplier<Instant> clock = () -> now[0];
40	
41	    private List<ParkingFloor> buildLot() {
42	        List<ParkingFloor> floors = new ArrayList<>();
43	        for (int f = 1; f <= 2; f++) {
44	            List<ParkingSpot> spots = new ArrayList<>();
45	            spots.add(new ParkingSpot("C" + f + "-1", f, SpotSize.COMPACT));
46	            spots.add(new ParkingSpot("C" + f + "-2", f, SpotSize.COMPACT));
47	            spots.add(new ParkingSpot("L" + f + "-1", f, SpotSize.LARGE));
48	            spots.add(new ParkingSpot("L" + f + "-2", f, SpotSize.LARGE));
49	            spots.add(new ParkingSpot("H" + f + "-1", f, SpotSize.HANDICAPPED));
50	            floors.add(new ParkingFloor(f, spots));
51	        }
52	        return floors;
53	    }
54	
55	    private ParkingLotService newLot() {
56	        return new ParkingLotService(buildLot(), new BestFitNearestStrategy(), clock, 200);
57	    }
58	
59	    // ─── Happy path ──────────────────────────────────────────────────────────
60	    @Test
61	    void parkReturnsTicketAndOccupiesSpot() {
62	        ParkingLotService lot = newLot();
63	        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
64	        assertTrue(t.id().startsWith("tkt-"));
65	        assertEquals("CAR-1", t.vehicle().licensePlate());
66	        assertEquals(1, lot.occupiedCount());
67	    }
68	
69	    @Test
70	    void unparkFreesSpotAndBillsRoundedUp() {
71	        ParkingLotService lot = newLot();
72	        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
73	        now[0] = now[0].plus(Duration.ofMinutes(90));   // 90 min -> 2 hours
74	        long fee = lot.unpark(t.id());
75	        assertEquals(400, fee, "90 min at 200c/hr rounds up to 2h");
76	        assertEquals(0, lot.occupiedCount());
77	    }
78	
79	    @Test
80	    void shortStayBillsMinimumOneHour() {
81	        ParkingLotService lot = newLot();
82	        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
83	        now[0] = now[0].plus(Duration.ofMinutes(5));    // 5 min -> still 1 hour
84	        assertEquals(200, lot.unpark(t.id()));
85	    }
86	
87	    // ─── Best-fit allocation ──────────────────────────────────────────────────
88	    @Test
89	    void motorcycleTakesCompactNotLarge() {
90	        ParkingLotService lot = newLot();
91	        Ticket moto = lot.park(new Vehicle("M-1", VehicleType.MOTORCYCLE));
92	        assertTrue(moto.spotId().startsWith("C"), "best fit puts moto in compact");
93	    }
94	
95	    @Test
96	    void handicappedVehicleOnlyTakesHandicappedSpot() {
97	        ParkingLotService lot = newLot();
98	        Ticket t = lot.park(new Vehicle("H-1", VehicleType.HANDICAPPED));
99	        assertTrue(t.spotId().startsWith("H"), "handicapped vehicle -> handicapped spot");
100	    }
101	
102	    @Test
103	    void regularCarNeverTakesHandicappedSpot() {
104	        // Build a lot whose ONLY free spot is handicapped; a car must be rejected.
105	        List<ParkingSpot> spots = new ArrayList<>();
106	        spots.add(new ParkingSpot("H1-1", 1, SpotSize.HANDICAPPED));
107	        ParkingLotService lot = new ParkingLotService(
108	            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
109	        assertThrows(NoSpotAvailableException.class,
110	            () -> lot.park(new Vehicle("CAR-1", VehicleType.CAR)));
111	    }
112	
113	    @Test
114	    void nearestFloorWins() {
115	        ParkingLotService lot = newLot();
116	        // First car should land on floor 1 (lower floor = nearer).
117	        Ticket t = lot.park(new Vehicle("CAR-1", VehicleType.CAR));
118	        assertEquals("L1-1", t.spotId(), "lowest floor, lowest id chosen first");
119	    }
120	
121	    // ─── Typed error paths ─────────────────────────────────────────────────────
122	    @Test
123	    void parkRejectsWhenFull() {
124	        ParkingLotService lot = newLot();
125	        long cars = lot.availableCountFor(VehicleType.CAR);
126	        for (int i = 0; i < cars; i++) {
127	            lot.park(new Vehicle("CAR-" + i, VehicleType.CAR));
128	        }
129	        assertThrows(NoSpotAvailableException.class,
130	            () -> lot.park(new Vehicle("OVERFLOW", VehicleType.CAR)));
131	    }
132	
133	    @Test
134	    void unparkUnknownTicketThrows() {
135	        ParkingLotService lot = newLot();
136	        assertThrows(TicketNotFoundException.class, () -> lot.unpark("tkt-nope"));
137	    }
138	
139	    @Test
140	    void unparkNullTicketThrows() {
141	        ParkingLotService lot = newLot();
142	        assertThrows(TicketNotFoundException.class, () -> lot.unpark(null));
143	    }
144	
145	    @Test
146	    void parkNullVehicleThrows() {
147	        ParkingLotService lot = newLot();
148	        assertThrows(ParkingException.class, () -> lot.park(null));
149	    }
150	
151	    @Test
152	    void blankPlateRejectedAtConstruction() {
153	        assertThrows(ParkingException.class, () -> new Vehicle("  ", VehicleType.CAR));
154	    }
155	
156	    // ─── Idempotency of spot.release ───────────────────────────────────────────
157	    @Test
158	    void releaseOnFreeSpotIsNoOp() {
159	        ParkingSpot spot = new ParkingSpot("L1-1", 1, SpotSize.LARGE);
160	        spot.release();                       // releasing a free spot
161	        assertEquals(SpotStatus.FREE, spot.status(), "release on free spot does nothing");
162	        spot.occupy(new Vehicle("CAR-1", VehicleType.CAR));
163	        spot.release();
164	        spot.release();                       // second release is a safe no-op
165	        assertEquals(SpotStatus.FREE, spot.status());
166	    }
167	
168	    // ─── Concurrency: the double-allocation race ───────────────────────────────
169	    @Test
170	    void concurrentParkNeverDoubleAllocatesSameSpot() throws Exception {
171	        int threads = 50, capacity = 5;
172	
173	        // Lot with exactly `capacity` LARGE spots — the precise scarce resource.
174	        List<ParkingSpot> spots = new ArrayList<>();
175	        for (int i = 0; i < capacity; i++) {
176	            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
177	        }
178	        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
179	            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
180	
181	        CyclicBarrier barrier = new CyclicBarrier(threads);   // stampede gate
182	        AtomicInteger wins = new AtomicInteger(0);
183	        AtomicInteger fulls = new AtomicInteger(0);
184	        AtomicInteger unexpected = new AtomicInteger(0);
185	        var wonSpots = ConcurrentHashMap.<String>newKeySet();
186	        ExecutorService pool = Executors.newFixedThreadPool(threads);
187	
188	        for (int i = 0; i < threads; i++) {
189	            final int id = i;
190	            pool.submit(() -> {
191	                try {
192	                    barrier.await();          // all 50 hit park() at the same moment
193	                    Ticket t = lot.park(new Vehicle("C-" + id, VehicleType.CAR));
194	                    wins.incrementAndGet();
195	                    wonSpots.add(t.spotId());
196	                } catch (NoSpotAvailableException e) {
197	                    fulls.incrementAndGet();
198	                } catch (Exception e) {
199	                    unexpected.incrementAndGet();
200	                }
201	            });
202	        }
203	        pool.shutdown();
204	        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS));
205	
206	        // STRICT post-state assertions:
207	        assertEquals(capacity, wins.get(), "exactly capacity threads parked");
208	        assertEquals(capacity, wonSpots.size(),
209	            "every win is a DIFFERENT spot — no double-allocation");
210	        assertEquals(threads - capacity, fulls.get(),
211	            "all others got the typed full error");
212	        assertEquals(0, unexpected.get(), "no surprise exceptions");
213	
214	        // Count occupied spots via the entity status, not a service-side set.
215	        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
216	        assertEquals(capacity, occupied, "exactly capacity spots OCCUPIED");
217	        assertEquals(capacity, lot.occupiedCount(), "registry matches occupied spots");
218	    }
219	
220	    @Test
221	    void concurrentParkUnparkChurnLeavesConsistentState() throws Exception {
222	        // Park and unpark repeatedly across many threads; the lot must end
223	        // empty with every spot FREE — proving no spot is leaked or stranded.
224	        int threads = 20;
225	        List<ParkingSpot> spots = new ArrayList<>();
226	        for (int i = 0; i < 10; i++) {
227	            spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
228	        }
229	        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
230	            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);
231	
232	        ExecutorService pool = Executors.newFixedThreadPool(threads);
233	        for (int i = 0; i < threads; i++) {
234	            pool.submit(() -> {
235	                for (int r = 0; r < 50; r++) {
236	                    try {
237	                        Ticket t = lot.park(new Vehicle("X", VehicleType.CAR));
238	                        lot.unpark(t.id());
239	                    } catch (NoSpotAvailableException ignored) {
240	                        // lot momentarily full — fine, just retry next round
241	                    }
242	                }
243	            });
244	        }
245	        pool.shutdown();
246	        assertTrue(pool.awaitTermination(20, TimeUnit.SECONDS));
247	
248	        assertEquals(0, lot.occupiedCount(), "lot empty after churn");
249	        long occupied = spots.stream().filter(s -> s.status() == SpotStatus.OCCUPIED).count();
250	        assertEquals(0, occupied, "no spot left stranded as OCCUPIED");
251	    }
252	}
