8	// One physical parking spot. This is the heart of the design and the heart of
9	// the concurrency story. Two ideas live here:
10	//   1. The spot is a tiny STATE MACHINE — it is the ONLY thing allowed to flip
11	//      its own status FREE <-> OCCUPIED. The service never writes status
12	//      directly, so an illegal jump is impossible by construction.
13	//   2. The spot carries its OWN lock. To park, you must hold THIS spot's lock.
14	//      Two threads grabbing two DIFFERENT spots never block each other — there
15	//      is no global lock and no global bottleneck. The lock is fine-grained,
16	//      one per spot.
17	// 🎙️ "Each spot owns its status AND its own lock. To take a spot you lock that
18	//      one spot, check it's free, occupy it, unlock. Two cars going for two
19	//      different spots run fully in parallel — the only time anyone waits is
20	//      when two cars fight over the exact same spot, and then the lock makes
21	//      one of them lose cleanly."
22	public class ParkingSpot {
23	
24	    private final String id;
25	    private final int floorNumber;
26	    private final SpotSize size;
27	
28	    // WHY: physical state lives on the spot — "what is in this spot right now"
29	    //      is the spot's own condition, not a relationship the service tracks.
30	    private SpotStatus status;
31	
32	    // WHY: who is parked here. Null when FREE. Lets unpark confirm we are
33	    //      freeing the right car and lets the demo print what was parked.
34	    @Nullable
35	    private Vehicle vehicle;
36	
37	    // WHY: the per-spot lock. This is the whole concurrency mechanism — each
38	    //      spot has its own ReentrantLock, so locking is fine-grained. We
39	    //      expose lock()/unlock() so the thread-safe service can wrap the
40	    //      check-and-occupy as one atomic step. The clean service never calls
41	    //      these; only the ThreadSafe subclass does.
42	    private final ReentrantLock lock = new ReentrantLock();
43	
44	    public ParkingSpot(String id, int floorNumber, SpotSize size) {
45	        this.id = id;
46	        this.floorNumber = floorNumber;
47	        this.size = size;
48	        this.status = SpotStatus.FREE;
49	        this.vehicle = null;
50	    }
51	
52	    public String id() {
53	        return id;
54	    }
55	
56	    public int floorNumber() {
57	        return floorNumber;
58	    }
59	
60	    public SpotSize size() {
61	        return size;
62	    }
63	
64	    public SpotStatus status() {
65	        return status;
66	    }
67	
68	    public boolean isFree() {
69	        return status == SpotStatus.FREE;
70	    }
71	
72	    @Nullable
73	    public Vehicle vehicle() {
74	        return vehicle;
75	    }
76	
77	    public ReentrantLock lock() {
78	        return lock;
79	    }
80	
81	    // WHY: the only way to put a car in a spot. We guard the transition: a spot
82	    //      that is already OCCUPIED cannot be occupied again. If that guard
83	    //      ever fires, it means two writers reached the same free spot — the
84	    //      lock is supposed to prevent that, so this is the state machine
85	    //      catching a bug the lock missed.
86	    // ⚠️ FOLLOW-UP: "Isn't this redundant with the lock?"
87	    //    → "It's belt and suspenders. The lock makes the race impossible; the
88	    //       state guard makes a logic bug LOUD instead of silent. If someone
89	    //       refactors the lock away, this throws instead of overwriting a car."
90	    public void occupy(Vehicle v) {
91	        if (status != SpotStatus.FREE) {
92	            throw new InvalidSpotStateException(
93	                "spot " + id + " is not FREE, cannot occupy");
94	        }
95	        this.status = SpotStatus.OCCUPIED;
96	        this.vehicle = v;
97	    }
98	
99	    // WHY: free the spot. Idempotent on purpose — calling it on an already-FREE
100	    //      spot does nothing rather than throwing. That keeps unpark and any
101	    //      future cleanup sweep safe to call without first re-checking state.
102	    // ⚠️ FOLLOW-UP: "Why is releasing twice a no-op instead of an error?"
103	    //    → "Because two cleanup paths could both try to free the same spot —
104	    //       a real unpark and a stale-ticket sweep. Whoever frees it first
105	    //       wins, the second call quietly does nothing. No spurious error on a
106	    //       perfectly correct double-free."
107	    public void release() {
108	        // WHY: only flip if currently occupied; otherwise leave it alone.
109	        if (status == SpotStatus.OCCUPIED) {
110	            this.status = SpotStatus.FREE;
111	            this.vehicle = null;
112	        }
113	    }
114	
115	    @Override
116	    public String toString() {
117	        return "Spot{" + id + ", floor=" + floorNumber + ", " + size
118	            + ", " + status + "}";
119	    }
120	}
