package com.interview.lld.parking;

import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.concurrent.*;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.function.Supplier;

import com.interview.lld.parking.model.*;
import com.interview.lld.parking.service.ThreadSafeParkingLotService;
import com.interview.lld.parking.strategy.BestFitNearestStrategy;

// Probe: hammer park/unpark with a SMALL pool of spots and MANY threads so the
// re-check-fails-recurse-under-lock path fires constantly. If nested locking can
// deadlock, this hangs and the watchdog reports it.
public class DeadlockProbe {
    public static void main(String[] args) throws Exception {
        Supplier<Instant> clock = () -> Instant.parse("2026-06-21T08:00:00Z");
        int spotsN = 3;       // tiny -> heavy contention -> frequent recursion
        int threads = 64;
        List<ParkingSpot> spots = new ArrayList<>();
        for (int i = 0; i < spotsN; i++) spots.add(new ParkingSpot("L1-" + i, 1, SpotSize.LARGE));
        ThreadSafeParkingLotService lot = new ThreadSafeParkingLotService(
            List.of(new ParkingFloor(1, spots)), new BestFitNearestStrategy(), clock, 200);

        ExecutorService pool = Executors.newFixedThreadPool(threads);
        AtomicInteger done = new AtomicInteger(0);
        AtomicInteger unexpected = new AtomicInteger(0);
        for (int i = 0; i < threads; i++) {
            pool.submit(() -> {
                for (int r = 0; r < 20000; r++) {
                    try {
                        Ticket t = lot.park(new Vehicle("X", VehicleType.CAR));
                        lot.unpark(t.id());
                    } catch (NoSpotAvailableException ignored) {
                    } catch (Throwable e) {
                        unexpected.incrementAndGet();
                        e.printStackTrace();
                    }
                }
                done.incrementAndGet();
            });
        }
        pool.shutdown();
        boolean ok = pool.awaitTermination(30, TimeUnit.SECONDS);
        System.out.println("terminated=" + ok + " done=" + done.get() + "/" + threads
            + " unexpected=" + unexpected.get()
            + " occupied=" + lot.occupiedCount());
        if (!ok) {
            System.out.println("!!! DID NOT TERMINATE — likely DEADLOCK or livelock !!!");
        }
