public class LockDepthProbe {
  static final ThreadLocal<Integer> depth = ThreadLocal.withInitial(()->0);
  static final AtomicInteger maxDepth = new AtomicInteger(0);

  // Subclass that mirrors ThreadSafeParkingLotService but counts how many distinct
  // spot guards a single thread holds at once (i.e., nesting from recursive park).
  static class Instrumented extends ParkingLotService {
    Instrumented(List<ParkingFloor> f, BestFitNearestStrategy s, Supplier<Instant> c, long r){super(f,s,c,r);}
    @Override protected <T> T withSpotGuard(ParkingSpot spot, Supplier<T> action){
      ReentrantLock lock = spot.lock();
      lock.lock();
      int d = depth.get()+1; depth.set(d);
      maxDepth.accumulateAndGet(d, Math::max);
      try { return action.get(); }
      finally { depth.set(depth.get()-1); lock.unlock(); }
    }
  }

